using Microsoft.ML;
using Microsoft.ML.Data;

namespace TicketClassifier.Services;

/// <summary>
/// Provides the category label names in the order the model assigns score indices.
/// </summary>
public class ModelLabelService
{
    public string[] Labels { get; }

    public ModelLabelService(IWebHostEnvironment env)
    {
        var modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
        var mlContext = new MLContext();
        var model = mlContext.Model.Load(modelPath, out var schema);

        var dummyData = mlContext.Data.LoadFromEnumerable(
            Array.Empty<Models.TicketInput>(), schema);
        var transformedSchema = model.Transform(dummyData).Schema;

        var scoreColumn = transformedSchema["Score"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        scoreColumn.GetSlotNames(ref slotNames);

        Labels = slotNames.DenseValues().Select(v => v.ToString()).ToArray();
    }
}

